/**
 * Retorna preços reais do posto pelo CNPJ.
 * Normaliza o CNPJ removendo pontuação e completando com zeros à esquerda.
 */
export function getPrecosPorCNPJ(cnpj: string): PrecoPostoCNPJ | null {
  if (!cnpj) return null
  const normalizado = cnpj.replace(/[^0-9]/g, '').padStart(14, '0')
  return PRECOS_POR_CNPJ[normalizado] || null
}

/**
 * Converte estrutura compacta para PostoReal.precos
 */
export function expandirPrecos(p: PrecoPostoCNPJ): Record<string, number> {
  const r: Record<string, number> = {}
  if (p.g)  r.gasolina = p.g
  if (p.ga) r.gasolinaAditivada = p.ga
  if (p.e)  r.etanol = p.e
  if (p.d)  r.diesel = p.d
  if (p.ds) r.dieselS10 = p.ds
  if (p.n)  r.gnv = p.n
  if (p.l)  r.glp = p.l
  return r
}
